```go
var mu sync.Mutex
var cache = make(map[string]int)

func update(key string, val int) {
    mu.Lock()
    cache[key] = val
    mu.Unlock()
}

func read(key string) int {
    return cache[key] // sometimes panics
}
```
What's wrong and how do I fix it?

